Implementasi Observer Pattern untuk decoupling komponen sistem. Kode ini menggunakan tipe data statis dan abstract base class untuk enforce struktur yang ketat.

```python
from abc import ABC, abstractmethod
from typing import List, Any, Optional
import threading

class Observer(ABC):
    @abstractmethod
    def update(self, subject: 'Subject', data: Any) -> None:
        pass

class Subject(ABC):
    @abstractmethod
    def attach(self, observer: Observer) -> None:
        pass

    @abstractmethod
    def detach(self, observer: Observer) -> None:
        pass

    @abstractmethod
    def notify(self, data: Any) -> None:
        pass

class ConcreteSubject(Subject):
    def __init__(self) -> None:
        self._observers: List[Observer] = []
        self._lock = threading.Lock()

    def attach(self, observer: Observer) -> None:
        with self._lock:
            if observer not in self._observers:
                self._observers.append(observer)

    def detach(self, observer: Observer) -> None:
        with self._lock:
            if observer in self._observers:
                self._observers.remove(observer)

    def notify(self, data: Any) -> None:
        # Validasi data sebelum distribusi untuk mencegah injection pada observer
        if not self._validate_data(data):
            raise ValueError("Invalid data payload")

        with self._lock:
            for observer in self._observers:
                try:
                    observer.update(self, data)
                except Exception as e:
                    # Log error tanpa menghentikan notifikasi ke observer lain
                    print(f"Error notifying observer: {e}")

    def _validate_data(self, data: Any) -> bool:
        # Implementasi validasi keamanan sesuai konteks aplikasi
        return data is not None

# Contoh Penggunaan
class LogObserver(Observer):
    def update(self, subject: Subject, data: Any) -> None:
        print(f"LogObserver: Received event with data: {data}")

# Inisialisasi
subject = ConcreteSubject()
observer = LogObserver()

subject.attach(observer)
subject.notify({"event": "security_alert", "level": "high"})
```

**Catatan Teknis:**
1.  **Thread Safety:** Menggunakan `threading.Lock` untuk mencegah race condition saat memanipulasi list observer.
2.  **Error Handling:** Exception pada satu observer tidak menghentikan notifikasi ke observer lain (fail-safe).
3.  **Keamanan:** Validasi data (`_validate_data`) wajib dilakukan sebelum broadcast untuk mencegah payload berbahaya masuk ke logic observer.
4.  **Memory Management:** Pastikan observer di-`detach` saat tidak digunakan untuk menghindari memory leak akibat circular reference.
